#!/usr/bin/env python3
"""Convert the policy report markdown to a professionally styled PDF."""

import markdown
from weasyprint import HTML

# Read markdown
with open("/home/user/rapport_beleidsherziening_woninghuur.md", "r") as f:
    md_text = f.read()

# Convert markdown to HTML
html_body = markdown.markdown(
    md_text,
    extensions=["tables", "fenced_code", "smarty"],
)

# Professional CSS styling
css = """
@page {
    size: A4;
    margin: 25mm 20mm 25mm 20mm;
    @bottom-center {
        content: "Pagina " counter(page) " van " counter(pages);
        font-size: 9pt;
        color: #666;
        font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
    }
    @top-right {
        content: "Onderbouwing Beleidsherziening Puntenstelsel";
        font-size: 8pt;
        color: #999;
        font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
    }
}

@page :first {
    @top-right { content: none; }
}

body {
    font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
    font-size: 10.5pt;
    line-height: 1.55;
    color: #1a1a1a;
    max-width: 100%;
}

h1 {
    font-size: 22pt;
    color: #1a3a5c;
    border-bottom: 3px solid #1a3a5c;
    padding-bottom: 8px;
    margin-top: 0;
    margin-bottom: 6px;
    page-break-after: avoid;
}

h1 + p {
    font-size: 11pt;
    color: #444;
    font-style: italic;
    margin-bottom: 20px;
}

h2 {
    font-size: 16pt;
    color: #1a3a5c;
    border-bottom: 1.5px solid #c0d0e0;
    padding-bottom: 4px;
    margin-top: 28px;
    margin-bottom: 10px;
    page-break-after: avoid;
}

h3 {
    font-size: 13pt;
    color: #2a5a8c;
    margin-top: 20px;
    margin-bottom: 8px;
    page-break-after: avoid;
}

h4 {
    font-size: 11pt;
    color: #3a6a9c;
    margin-top: 16px;
    margin-bottom: 6px;
    page-break-after: avoid;
}

p {
    margin: 6px 0;
    text-align: left;
}

strong {
    color: #1a1a1a;
}

em {
    color: #444;
}

table {
    width: 100%;
    border-collapse: collapse;
    margin: 12px 0;
    font-size: 9.5pt;
    page-break-inside: avoid;
}

thead {
    background-color: #1a3a5c;
    color: white;
}

th {
    padding: 8px 10px;
    text-align: left;
    font-weight: 600;
    font-size: 9pt;
    border: 1px solid #1a3a5c;
}

td {
    padding: 6px 10px;
    border: 1px solid #d0d0d0;
    vertical-align: top;
}

tr:nth-child(even) {
    background-color: #f5f8fc;
}

tr:nth-child(odd) {
    background-color: #ffffff;
}

/* Highlight rows with bold content */
tr td strong {
    color: #1a3a5c;
}

blockquote {
    border-left: 4px solid #e74c3c;
    background-color: #fdf2f2;
    padding: 12px 16px;
    margin: 14px 0;
    font-style: normal;
    color: #333;
    page-break-inside: avoid;
}

blockquote strong {
    color: #c0392b;
}

blockquote p {
    margin: 4px 0;
}

ul, ol {
    margin: 8px 0;
    padding-left: 24px;
}

li {
    margin: 4px 0;
}

code {
    font-family: 'Consolas', 'Courier New', monospace;
    font-size: 9pt;
    background-color: #f0f4f8;
    padding: 2px 5px;
    border-radius: 3px;
}

pre {
    background-color: #f0f4f8;
    border: 1px solid #d0d8e0;
    border-radius: 4px;
    padding: 14px;
    font-size: 9pt;
    overflow-wrap: break-word;
    white-space: pre-wrap;
    page-break-inside: avoid;
}

pre code {
    background: none;
    padding: 0;
}

hr {
    border: none;
    border-top: 1.5px solid #c0d0e0;
    margin: 24px 0;
}

a {
    color: #2a5a8c;
    text-decoration: none;
}

a:hover {
    text-decoration: underline;
}

/* Special styling for the summary comparison table */
table:has(th:first-child:contains("Scenario")) {
    font-size: 8.5pt;
}

/* Ensure key finding boxes stand out */
blockquote + hr {
    margin-top: 8px;
}
"""

# Wrap in full HTML document
full_html = f"""<!DOCTYPE html>
<html lang="nl">
<head>
    <meta charset="utf-8">
    <style>{css}</style>
</head>
<body>
{html_body}
</body>
</html>"""

# Generate PDF
output_path = "/home/user/rapport_beleidsherziening_woninghuur.pdf"
HTML(string=full_html).write_pdf(output_path)
print(f"PDF generated: {output_path}")

# Check file size
import os
size = os.path.getsize(output_path)
print(f"File size: {size:,} bytes ({size/1024:.0f} KB)")

