    margin-bottom: 8px;
    page-break-after: avoid;
}

h4 {
    font-size: 11pt;
    color: #3a6a9c;
    margin-top: 16px;
    margin-bottom: 6px;
    page-break-after: avoid;
}

/* Each lettered scenario starts on its own page */
h4.scenario-heading {
    page-break-before: always;
}

p {
    margin: 6px 0;
    text-align: left;
}

strong {
    color: #1a1a1a;
}

em {
    color: #444;
}

