with open("/home/user/rapport_beleidsherziening_woninghuur.md", "r") as f:
    md_text = f.read()

# Convert markdown to HTML
html_body = markdown.markdown(
    md_text,
    extensions=["tables", "fenced_code", "smarty"],
)

# Post-process: add a class to h4 elements that start with "Scenario " 
# so we can apply page-break-before to each lettered scenario
import re
# Each scenario heading looks like: <h4>Scenario A – ...</h4>
# We want to add page-break-before to these — but NOT to Scenario A,
# because A should stay on the same page as the h3 "4.2" heading above it.
html_body = re.sub(
    r'<h4>(Scenario [B-I]\s*–)',
    r'<h4 class="scenario-heading">\1',
    html_body
)

